function ToastDemo() {
  const [toasts, setToasts] = useState([]);
  const timers = useRef({});

  const addToast = (message, type = 'info') => {
    const id = Date.now();
    setToasts(prev => [...prev, { id, message, type }]);
    timers.current[id] = setTimeout(() => removeToast(id), 5000);
  };

  const removeToast = (id) => {
    clearTimeout(timers.current[id]);
    delete timers.current[id];
    setToasts(prev => prev.filter(t => t.id !== id));
  };

  const pause = (id) => clearTimeout(timers.current[id]);
  const resume = (id) => {
    timers.current[id] = setTimeout(() => removeToast(id), 5000);
  };

  return (
    <div>
      <button onClick={() => addToast('저장되었습니다.', 'success')}>저장</button>

      <div className="toast-region" aria-label="알림">
        {toasts.map(t => (
          <div
            key={t.id}
            role={t.type === 'error' ? 'alert' : 'status'}
            aria-live={t.type === 'error' ? 'assertive' : 'polite'}
            onMouseEnter={() => pause(t.id)}
            onMouseLeave={() => resume(t.id)}
            onFocus={() => pause(t.id)}
            onBlur={() => resume(t.id)}
            className={`toast toast-${t.type}`}
          >
            <span aria-hidden>{/* icon */}</span>
            <span>{t.message}</span>
            <button onClick={() => removeToast(t.id)} aria-label="알림 닫기">×</button>
          </div>
        ))}
      </div>
    </div>
  );
}
